// Extract appointment + contact data from GHL webhook
const data = $input.first().json;
const body = data.body || data;

const contactId = body.contactId || body.contact_id || '';
const contactName = body.contactName || body.contact?.name || body.first_name || 'there';
const contactPhone = body.contactPhone || body.contact?.phone || '';
const contactEmail = body.contactEmail || body.contact?.email || '';
const locationId = body.locationId || body.location_id || '';
const appointmentId = body.id || body.appointmentId || '';
const calendarName = body.calendarName || body.calendar?.name || 'your appointment';
const appointmentTime = body.startTime || body.start_time || '';
const status = body.status || 'no_show';

// Format the time nicely if available
let timeStr = '';
if (appointmentTime) {
  try {
    const d = new Date(appointmentTime);
    timeStr = d.toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric', month: 'short' });
  } catch(e) {
    timeStr = '';
  }
}

return [{
  json: {
    contactId,
    contactName,
    contactPhone,
    contactEmail,
    locationId,
    appointmentId,
    calendarName,
    appointmentTime: timeStr,
    status,
    chaseAt: new Date(Date.now() + 10 * 60 * 1000).toISOString()
  }
}];

// Build the chase message - varies by attempt
const data = $input.first().json;
const name = data.contactName || 'there';
const firstName = name.split(' ')[0];
const time = data.appointmentTime;

// Friendly, not guilt-trippy
const messages = [
  `Hey ${firstName}, noticed you couldn't make it${time ? ' on ' + time : ''} - no stress at all. Want me to rebook you for another day this week?`,
  `Hey ${firstName}, just following up - life gets busy, I get it. If you still want to get booked in, I can find you a new slot. Just say the word.`,
  `Hey ${firstName}, last one from me on this - if the timing wasn't right, no worries. The door's always open when you're ready. Just reply and I'll sort a new time.`
];

// Default to first message (chase #1)
const message = messages[0];

return [{
  json: {
    ...data,
    chaseMessage: message,
    chaseNumber: 1
  }
}];

